sql:
SELECT SUM(disbursement_amount) AS total_disbursement
FROM loan_disbursements
WHERE loan_id = '1';

SELECT loan_product_name
FROM loan_products
WHERE loan_product_id = 0;

external_knowledge:
- "largest loans" refers to the loan with the highest loan amount for each applicant;
- "approved loans" refers to loans with a loan status of 'approved';
- The assumption is that each applicant can have multiple loans, and we are interested in the largest one.
